:root {
  --primary: oklch(55% 0.2 250);
  --primary-hover: oklch(48% 0.2 250);
  --primary-light: oklch(95% 0.03 250);
  --primary-dark: oklch(25% 0.1 250);
  /* ...shades for every color */
}

:root {
  --space-xs: clamp(...);
  --space-s:  clamp(...);
  --space-m:  clamp(...);
  --space-l:  clamp(...);
  --space-xl: clamp(...);
  --space-xxl: clamp(...);
}

/* Automatic — no classes needed */
.smart-spacing > * + * {
  margin-block-start: var(--flow-spacing);
}
.smart-spacing > :is(h1,h2,h3,h4,h5,h6) {
  margin-block-start: var(--heading-spacing);
}
